  "das Fieber": { sk: "horúčka", example: "Sie hatte gestern Abend noch schrecklich hohes brennendes Fieber.", exampleSk: "Včera večer mala ešte strašne vysokú pálivú horúčku." },
  "genau": { sk: "presne, presne tak", example: "Das ist ganz genau das, was ich dir eigentlich auch sagen wollte.", exampleSk: "To je celkom úplne presne to isté, čo som ti chcel vlastne rovnako povedať i ja." },
