  // Chapter 70: Beim Arzt
  "sich etwas an|schauen": { sk: "niečo si pozrieť / prezrieť", example: "Darf ich mir das Foto auch noch mal genauer anschauen?", exampleSk: "Smiem si aj ja túto fotku ešte raz presnejšie pozrieť?" },
  "die Apotheke": { sk: "lekáreň", example: "Meine Mutter wollte noch in der Apotheke ihre Medikamente einlösen.", exampleSk: "Moja mama si chcela ešte v lekárni vybrať lieky." },
  "die Behandlung": { sk: "ošetrenie, liečba", example: "Die kurze Behandlung beim Doktor gestern lief wirklich optimal.", exampleSk: "Krátke ošetrenie včera u doktora prebehlo skutočne optimálne." },
  "der Behandlungsraum": { sk: "ošetrovňa (ambulancia)", example: "Bitte warten Sie im Behandlungsraum auf die Ärztin.", exampleSk: "Počkajte, prosím, v ošetrovni na lekárku." },
  "Bis gleich!": { sk: "Zatiaľ! Hneď som späť! (Do skorého videnia!)", example: "Ich hole noch schnell Kaffee. Bis gleich!", exampleSk: "Ešte rýchlo zoberiem kávu. Zatiaľ (hneď som tu)!" },
  "Bitte schön!": { sk: "Nech sa páči! / Prosím pekne!", example: "Hier ist ihr bestellter Kaffee, bitte schön!", exampleSk: "Tu je vaša objednaná káva, nech sa páči!" },
  "doof": { sk: "hlúpy / blbý", example: "Das ist aber auch eine verdammt doofe Angewohnheit von dir.", exampleSk: "To je proste tiež tvoj prekliato hlúpy zvyk." },
  "dürfen": { sk: "smieť", example: "Darf man in dieser kleinen Bäckerei laut telefonieren?", exampleSk: "Smie sa v tejto malej pekárni nahlas telefonovať?" },
  "etwas": { sk: "niečo / trochu", example: "Hast du vielleicht noch etwas Zeit für ein kurzes Gespräch?", exampleSk: "Máš azda ešte trochu času na krátky rozhovor?" },
  "sich auf etwas/jemanden freuen": { sk: "tešiť sa na (niečo/niekoho)", example: "Ich freue mich schon sehr auf meinen alten Papa.", exampleSk: "Už sa veľmi teším na môjho starého otca (tatu)." },
  "gar nicht": { sk: "vôbec (nie)", example: "Ich mag dieses laute Konzert überhaupt gar nicht.", exampleSk: "Tento hlučný koncert sa mi vôbec nepáči (vôbec ho nemám rád)." },
  "gebrochen": { sk: "zlomený", example: "Sein großer dicker Zeh war wohl unglücklich gebrochen.", exampleSk: "Jeho veľký hrubý palec na nohe bol asi nešťastne zlomený." },
  "gleich": { sk: "o chvíľu, hneď", example: "Ich komme gleich zurück, warte bitte hier am Auto.", exampleSk: "O chvíľu sa vrátim späť, počkaj, prosím, tu pri aute." },
  "der Hustensaft": { sk: "sirup proti kašľu", example: "Dieser süße Hustensaft schmeckt den Kindern absolut nicht.", exampleSk: "Tento sladký sirup proti kašľu deťom absolútne nechutí." },
  "Ich habe starke Schmerzen.": { sk: "Mám silné bolesti.", example: "Herr Doktor, ich habe starke Schmerzen im rechten Knie.", exampleSk: "Pán doktor, mám silné bolesti v pravom kolene." },
  "die Krankenversicherung": { sk: "zdravotné poistenie", example: "Sicherlich brauchst du in Deutschland eine gute Krankenversicherung.", exampleSk: "V Nemecku nepochybne potrebuješ dobré zdravotné poistenie." },
  "leise": { sk: "ticho, potichu", example: "Seid bitte leise im Museum, die Leute gucken schon böse.", exampleSk: "Buďte prosím potichu v múzeu, ľudia sa už pozerajú nahnevane." },
  "das Medikament": { sk: "liek (medikament)", example: "Diese Medikamente musst du täglich vor dem Frühstück einnehmen.", exampleSk: "Tieto lieky musíš užívať denne pred raňajkami." },
  "die Praxis": { sk: "ambulancia (lekárska prax)", example: "Die Praxis meiner lieben Ärztin hat heute unerwartet geschlossen.", exampleSk: "Ambulancia mojej drahej lekárky má dnes neočakávane zatvorené." },
  "das Rezept": { sk: "lekársky predpis, recept", example: "Geben Sie dieses wichtige Rezept gleich bei der Apotheke ab.", exampleSk: "Odovzdajte tento dôležitý recept okamžite (hneď) v lekárni." },
  "etwas/jemanden röntgen": { sk: "zröntgenovať", example: "Der Arzt wollte meinen rechten Fuß sicherheitshalber etwas röntgen.", exampleSk: "Lekár chcel pre istotu môj pravý nohu trocha zröntgenovať." },
  "schade": { sk: "škoda", example: "Schade drum, dass du leider nicht kommen konntest.", exampleSk: "To je škoda, že si žiaľ nemohol prísť." },
  "sofort": { sk: "ihneď (okamžite)", example: "Du musst mir bitte nun sofort auf meine einfache Nachricht antworten.", exampleSk: "Musíš mi prosím teraz ihneď na moju jednoduchú správu odpovedať." },
  "die Sprechstunde": { sk: "úradné (ordinačné) hodiny", example: "Die Sprechstunde beim Hausarzt beginnt meistens um neun Uhr früh.", exampleSk: "Ordinačné hodiny u obvodného lekára zväčša začínajú o deviatej ráno." },
  "die Sprechstundenhilfe": { sk: "sestrička v ambulancii (asistentka lekára)", example: "Die Sprechstundenhilfe hat mir einen neuen Termin gegeben.", exampleSk: "Sestrička v ambulancii mi dala nový termín." },
  "die Tablette": { sk: "tableta", example: "Sie müssen jeden Morgen eine Tablette mit viel Wasser einnehmen.", exampleSk: "Každé ráno musíte zapiť jednu tabletu veľkým množstvom vody." },
  "über": { sk: "cez, nad (o niečom)", example: "Die Ärzte sprachen leise über die anstehende kurze Behandlung.", exampleSk: "Lekári sa potichu rozprávali o nadchádzajúcom krátkom ošetrení." },
  "die Versichertenkarte": { sk: "kartička poistenca", example: "Bitte geben Sie mir kurz Ihre Versichertenkarte.", exampleSk: "Dajte mi, prosím, na chvíľu vašu kartičku poistenca." },
  "vorbei|kommen": { sk: "zastaviť sa (zbehnúť k niekomu)", example: "Können Sie heute Nachmittag in der Praxis vorbeikommen?", exampleSk: "Môžete sa dnes poobede zastaviť v ambulancii?" },
  "das Wartezimmer": { sk: "čakáreň", example: "Das Wartezimmer war heute wieder ziemlich voll.", exampleSk: "Čakáreň bola dnes opäť dosť plná." },
  "der Zahnarzt": { sk: "zubár", example: "Ich muss bald dringend wieder zum Zahnarzt gehen.", exampleSk: "Musím ísť čoskoro znova súrne k zubárovi." },
  "die Zahnärztin": { sk: "zubárka", example: "Die neue Zahnärztin ist wirklich sehr nett und vorsichtig.", exampleSk: "Nová zubárka je naozaj veľmi milá a opatrná." },
  "etwas zeigen": { sk: "ukázať niečo", example: "Können Sie mir bitte noch einmal genau zeigen, wo es wehtut?", exampleSk: "Môžete mi prosím ešte raz presne ukázať, kde to bolí?" },

  // Chapter 71: Gute Besserung!
  "bewusstlos": { sk: "v bezvedomí", example: "Der Mann war nach dem Unfall kurzzeitig bewusstlos.", exampleSk: "Muž bol po nehode na chvíľu v bezvedomí." },
