  "bremsen": { sk: "brzdiť", example: "Du musst hier an der Kreuzung unbedingt rechtzeitig bremsen.", exampleSk: "Na tejto križovatke musíš bezpodmienečne včas brzdiť." },
  "die Gehirnerschütterung": { sk: "otras mozgu", example: "Nach dem Sturz hatte er eine leichte Gehirnerschütterung.", exampleSk: "Po páde mal ľahký otras mozgu." },
  "Gern geschehen!": { sk: "Niet za čo! (Rado sa stalo!)", example: "Danke für die Hilfe! - Gern geschehen!", exampleSk: "Ďakujem za pomoc! - Rado sa stalo!" },
