  "der Gips": { sk: "sadra", example: "Er muss seinen linken Arm nun sechs Wochen lang im Gips tragen.", exampleSk: "Teraz musí nosiť ľavú ruku v sadre šesť týždňov." },
  "Gute Besserung!": { sk: "Skoré uzdravenie!", example: "Ich habe gehört, du bist krank. Gute Besserung!", exampleSk: "Počul som, že si chorý. Skoré uzdravenie!" },
  "der Krankenwagen": { sk: "sanitka", example: "Der Krankenwagen war unglaublich schnell am Tatort.", exampleSk: "Sanitka bola na mieste činu neuveriteľne rýchlo." },
