  "der Patient": { sk: "pacient", example: "Der ältere Patient liegt aktuell drüben in Zimmer vier.", exampleSk: "Ten starší pacient momentálne leží naproti v izbe číslo štyri." },
  "die Patientin": { sk: "pacientka", example: "Die neue Patientin wird gerade vom Chefarzt untersucht.", exampleSk: "Novú pacientku práve vyšetruje vrchný lekár." },
  "plötzlich": { sk: "zrazu, náhle", example: "Plötzlich fing es extrem stark an zu regnen.", exampleSk: "Zrazu začalo extrémne silno pršať." },
  "jemanden/etwas untersuchen": { sk: "vyšetriť (niekoho/niečo)", example: "Der Arzt muss deinen Fuß wirklich noch mal gründlich untersuchen.", exampleSk: "Lekár ti musí nohu skutočne ešte raz dôkladne vyšetriť." },
  "verletzt": { sk: "zranený (-á)", example: "Glücklicherweise war bei dem Unfall niemand ernsthaft verletzt.", exampleSk: "Našťastie nebol pri nehode nikto vážne zranený." },
  "zum Glück": { sk: "našťastie", example: "Zum Glück ist uns bei dem furchtbaren Sturm nichts Schlimmes passiert.", exampleSk: "Našťastie sa nám pri tej strašnej búrke nič zlé nestalo." },

  // Chapter 72: Nehmen Sie …
  "etwas ändern": { sk: "niečo zmeniť", example: "Wir müssen unbedingt sofort etwas an diesem alten Plan ändern.", exampleSk: "Musíme na tomto starom pláne bezpodmienečne okamžite niečo zmeniť." },
  "der Arzthelfer": { sk: "zdravotný asistent / brat v ambulancii", example: "Der freundliche Arzthelfer hat mir sofort schnell den Blutdruck gemessen.", exampleSk: "Priateľský zdravotný asistent mi okamžite a rýchlo zmeral krvný tlak." },
  "die Arzthelferin": { sk: "zdravotná asistentka / zostrička v ambulancii", example: "Die nette Arzthelferin rief mich endlich ins Behandlungszimmer.", exampleSk: "Milá asistentka ma konečne zavolala do ošetrovne." },
