  "bedeuten": { sk: "znamenať", example: "Weißt du eigentlich, was dieses merkwürdige Zeichen da oben bedeutet?", exampleSk: "Vieš ty vôbec, čo to zvláštne znamienko tam hore znamená?" },
  "etwas benutzen": { sk: "použiť (niečo)", example: "Darf ich mal bitte kurz schnell dein neues Handy benutzen?", exampleSk: "Smiem na chvíľu rýchlo použiť tvoj nový mobil?" },
  "das Blut": { sk: "krv", example: "Viele Menschen können verständlicherweise absolut kein Blut sehen.", exampleSk: "Mnoho ľudí pochopiteľne vôbec neznesie (nemôže vidieť) krv." },
  "Blut ab|nehmen": { sk: "vziať krv", example: "Der Arzt wird dir morgen früh erst einmal etwas Blut abnehmen.", exampleSk: "Lekár ti zajtra ráno najprv trošku vezme krv (na rozbor)." },
  "der Blutdruck": { sk: "krvný tlak", example: "Mein Blutdruck ist wegen dem vielen starken Kaffee oft viel zu hoch.", exampleSk: "Môj krvný tlak je kvôli priveľa silnej kávæ často až príliš vysoký." },
  "Danke für Ihre Hilfe.": { sk: "Ďakujem za vašu pomoc.", example: "Das war wirklich sehr nett, danke für Ihre großartige Hilfe.", exampleSk: "Bolo to skutočne veľmi milé, ďakujem za vašu skvelú pomoc." },
  "ein|atmen": { sk: "nadýchnuť sa", example: "Bitte bleiben Sie ganz ruhig stehen und atmen Sie tief ein.", exampleSk: "Zostaňte prosím celkom pokojne stáť a hlboko sa nadýchnite." },
  "die Entzündung": { sk: "zápal", example: "Er hat eine schmerzhafte schwere Entzündung im neuen linken Handgelenk.", exampleSk: "Má bolestivý ťažký zápal v ľavom zápästí." },
  "jemanden krank|schreiben": { sk: "vypísať (na práceneschopnosť)", example: "Der Arzt hat mich wegen der schlimmen Erkältung leider für eine Woche krankgeschrieben.", exampleSk: "Lekár ma pre tú hroznú nádchu (chorobu) vypísal žiaľ na jeden týždeň." },
  "die Krankschreibung": { sk: "práceneschopnosť (papierovka od lekára / PN)", example: "Vergiss auf gar keinen Fall, deine aktuelle Krankschreibung rechtzeitig beim Chef abzugeben.", exampleSk: "V žiadnom prípade nezabudni včas odovzdať tvoju aktuálnu PNku šéfovi." },
  "die Krücke": { sk: "barla", example: "Er muss wegen seinem kaputten Fuß leider schon seit Tagen an Krücken gehen.", exampleSk: "Pre jeho zničenú (zlomenú) nohu musí žiaľ už dni chodiť na barlách." },
